    // Resolve springs — damping param here is damping ratio (0.9 or 1.0)
    // Convert damping ratio to damping coefficient: c = ζ × 2 × sqrt(k × m)
    function springCSS(stiffness, dampingRatio) {
      const mass = 1;
      const damping = dampingRatio * 2 * Math.sqrt(stiffness * mass);
      return springToLinear(stiffness, damping, mass);
    }

    const spatialFast = springCSS(1400, 0.9);
    const effectsFast = springCSS(3800, 1.0);
